#include<bits/stdc++.h>
using namespace std;
int fa[40010],cnt,n,m;
int u[2000010],v[2000010],w[2000010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    fa[find(x)]=find(y);
}
bool check(int mid)
{
    for(int i=1;i<=n;i++)
    {
        fa[i]=i;
        fa[i+n]=i+n;
    }
    for(int i=1;i<=m;i++)
    {
        if(w[i]>mid)
        {
            if(find(u[i])==find(v[i])||find(u[i]+n)==find(v[i]+n))
            {
                return false;
            }
            merge(u[i],v[i]+n);
            merge(u[i]+n,v[i]);
        }
    }
    // for(int i=1;i<=n;i++)
    // {
    //     if(find(i)==find(i+n))
    //     {
    //         return false;
    //     }
    // }
    return true;
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d%d",&u[i],&v[i],&w[i]);
    }
    int l=0,r=1e9,best=1e9;
    while(l<=r)
    {
        int mid=(l+r)>>1;
        if(check(mid))
        {
            r=mid-1;
            best=mid;
        }
        else
        {
            l=mid+1;
        }
    }
    printf("%d",best);
    return 0;
}
